{
  "name": "HijabStyle AI",
  "description": "Your personal AI-powered virtual stylist for Hijab OOTD inspiration, mix-and-match advice, and trend analysis.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppMode {
  HOME = 'HOME',
  GENERATOR = 'GENERATOR',
  ANALYZER = 'ANALYZER',
  CHAT = 'CHAT'
}

export interface StylingPreferences {
  occasion: string;
  style: string;
  colors: string;
  hijabType: string; // e.g., Pashmina, Square, Turban, Syar'i
}

export interface GeneratedLook {
  imageUrl?: string;
  description: string;
  tips: string[];
  items: string[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  image?: string;
}

export const HIJAB_STYLES = [
  'Casual Chic',
  'Formal Elegant',
  'Streetwear',
  'Bohemian',
  'Office Wear',
  'Wedding Guest',
  'Sporty Modest',
  'Minimalist'
];

export const HIJAB_TYPES = [
  'Pashmina',
  'Square Scarf (Segi Empat)',
  'Instant Hijab',
  'Syar\'i',
  'Turban Style',
  'Khimar'
];

import { GoogleGenAI, Type } from "@google/genai";
import { GeneratedLook, StylingPreferences } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to convert File to Base64
export const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];
      resolve({
        inlineData: {
          data: base64Data,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Generates a text styling advice and a prompt for image generation.
 */
export const generateStylingAdvice = async (prefs: StylingPreferences): Promise<GeneratedLook> => {
  const ai = getClient();

  const prompt = `
    Act as a professional Muslimah fashion stylist. Create a complete outfit recommendation based on:
    - Occasion: ${prefs.occasion}
    - Style: ${prefs.style}
    - Color Palette: ${prefs.colors}
    - Preferred Hijab Type: ${prefs.hijabType}

    Output valid JSON with the following structure:
    {
      "description": "A vivid, inspiring description of the outfit.",
      "tips": ["Tip 1", "Tip 2", "Tip 3"],
      "items": ["Item 1", "Item 2", "Item 3", "Item 4"],
      "imagePrompt": "A highly detailed prompt to generate a photorealistic image of this outfit worn by a model with a hijab, ensuring modesty and style."
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
            type: Type.OBJECT,
            properties: {
                description: { type: Type.STRING },
                tips: { type: Type.ARRAY, items: { type: Type.STRING } },
                items: { type: Type.ARRAY, items: { type: Type.STRING } },
                imagePrompt: { type: Type.STRING }
            }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from Stylist AI");

    const data = JSON.parse(text);
    return data;

  } catch (error) {
    console.error("Error generating styling advice:", error);
    throw error;
  }
};

/**
 * Generates an image of the outfit based on a description.
 */
export const generateOutfitImage = async (imagePrompt: string): Promise<string | undefined> => {
    const ai = getClient();
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [{ text: imagePrompt + ", high quality, photorealistic, fashion photography, 8k, modest fashion" }]
            },
            config: {
                imageConfig: {
                    aspectRatio: "3:4"
                }
            }
        });

        // Extract image
        for (const part of response.candidates?.[0]?.content?.parts || []) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        return undefined;
    } catch (error) {
        console.error("Error generating image:", error);
        return undefined; // Fail gracefully for image
    }
};

/**
 * Analyzes an uploaded photo and provides advice.
 */
export const analyzeUploadedLook = async (file: File, query: string): Promise<string> => {
    const ai = getClient();
    const imagePart = await fileToGenerativePart(file);

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    imagePart,
                    { text: `You are a Hijab fashion stylist. Analyze this image. User question: "${query}". Provide specific, helpful advice on color matching, style improvement, or hijab styling. Be encouraging and polite.` }
                ]
            }
        });

        return response.text || "I couldn't analyze the image clearly. Please try again.";
    } catch (error) {
        console.error("Error analyzing look:", error);
        throw error;
    }
};

import React from 'react';
import { AppMode } from '../types';
import { Sparkles, Camera, MessageCircle, Home } from 'lucide-react';

interface NavigationProps {
  currentMode: AppMode;
  setMode: (mode: AppMode) => void;
}

const Navigation: React.FC<NavigationProps> = ({ currentMode, setMode }) => {
  const navItems = [
    { mode: AppMode.HOME, icon: Home, label: 'Home' },
    { mode: AppMode.GENERATOR, icon: Sparkles, label: 'Style Gen' },
    { mode: AppMode.ANALYZER, icon: Camera, label: 'Analyzer' },
    { mode: AppMode.CHAT, icon: MessageCircle, label: 'Chat' },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t border-stone-200 shadow-lg z-50 md:top-0 md:bottom-auto">
      <div className="max-w-4xl mx-auto px-4">
        <div className="flex justify-around md:justify-center md:gap-12 py-3">
          {navItems.map((item) => {
            const isActive = currentMode === item.mode;
            return (
              <button
                key={item.mode}
                onClick={() => setMode(item.mode)}
                className={`flex flex-col md:flex-row items-center gap-1 md:gap-2 p-2 rounded-lg transition-all duration-300 ${
                  isActive 
                    ? 'text-rose-600 bg-rose-50' 
                    : 'text-stone-500 hover:text-stone-800 hover:bg-stone-50'
                }`}
              >
                <item.icon size={24} className={isActive ? 'stroke-[2.5px]' : 'stroke-2'} />
                <span className={`text-xs md:text-sm font-medium ${isActive ? 'font-bold' : ''}`}>
                  {item.label}
                </span>
              </button>
            );
          })}
        </div>
      </div>
    </nav>
  );
};

export default Navigation;

import React, { useState } from 'react';
import { HIJAB_STYLES, HIJAB_TYPES, StylingPreferences, GeneratedLook } from '../types';
