      let imageUrl: string | undefined = undefined;

      if (imagePrompt) {
          imageUrl = await generateOutfitImage(imagePrompt);
      }

      setResult({
          ...data,
          imageUrl
      });

    } catch (err) {
      setError("Failed to generate style. Please check your connection and try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
