      {/* Form Section */}
      <div className="bg-white p-6 md:p-8 rounded-2xl shadow-sm border border-stone-100 space-y-5">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
          <div className="space-y-2">
            <label className="text-sm font-semibold text-stone-700">Occasion</label>
            <input
              type="text"
              value={prefs.occasion}
              onChange={(e) => setPrefs({ ...prefs, occasion: e.target.value })}
