              placeholder="e.g. Wedding Guest, Office, Coffee Date"
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-semibold text-stone-700">Style Vibe</label>
            <select
              value={prefs.style}
              onChange={(e) => setPrefs({ ...prefs, style: e.target.value })}
