              placeholder="e.g. Earthy, Pastels, Monochrome Black"
            />
          </div>

           <div className="space-y-2">
            <label className="text-sm font-semibold text-stone-700">Preferred Hijab</label>
            <select
              value={prefs.hijabType}
              onChange={(e) => setPrefs({ ...prefs, hijabType: e.target.value })}
