export default StyleGenerator;

import React, { useState, useRef } from 'react';
import { Camera, Upload, X, Loader2, Send } from 'lucide-react';
import { analyzeUploadedLook } from '../services/gemini';

const OutfitAnalyzer: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [query, setQuery] = useState("What hijab color matches this outfit best?");
  const [loading, setLoading] = useState(false);
  const [analysis, setAnalysis] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setPreview(URL.createObjectURL(selectedFile));
      setAnalysis(null);
    }
  };

  const clearFile = () => {
    setFile(null);
    setPreview(null);
    setAnalysis(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAnalyze = async () => {
    if (!file) return;
    setLoading(true);
    try {
      const result = await analyzeUploadedLook(file, query);
      setAnalysis(result);
    } catch (error) {
      setAnalysis("Sorry, I had trouble analyzing that image. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
       <header className="text-center space-y-2">
        <h2 className="text-3xl font-serif font-bold text-stone-800">Outfit Analyzer</h2>
        <p className="text-stone-500">Upload a photo of your clothes and get instant hijab pairing advice.</p>
      </header>

      <div className="bg-white rounded-2xl shadow-sm border border-stone-100 overflow-hidden">
        {/* Upload Area */}
        <div className="p-6 md:p-8">
            {!preview ? (
                <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="border-2 border-dashed border-stone-300 rounded-2xl h-64 flex flex-col items-center justify-center cursor-pointer hover:bg-stone-50 transition-colors group"
                >
                    <div className="bg-stone-100 p-4 rounded-full mb-4 group-hover:bg-rose-50 group-hover:text-rose-500 transition-colors text-stone-400">
                        <Upload size={32} />
                    </div>
                    <p className="text-stone-600 font-medium">Click to upload photo</p>
                    <p className="text-stone-400 text-sm mt-1">or drag and drop</p>
                </div>
            ) : (
                <div className="relative rounded-2xl overflow-hidden bg-stone-100 border border-stone-200">
                    <img src={preview} alt="Upload preview" className="w-full max-h-[400px] object-contain mx-auto" />
                    <button 
                        onClick={clearFile}
                        className="absolute top-4 right-4 bg-white/90 p-2 rounded-full shadow-sm hover:bg-red-50 hover:text-red-500 transition-all"
                    >
                        <X size={20} />
                    </button>
                </div>
            )}
            <input 
                ref={fileInputRef}
                type="file" 
                accept="image/*" 
                onChange={handleFileChange} 
                className="hidden" 
            />
        </div>

        {/* Query & Action */}
        <div className="border-t border-stone-100 p-6 md:p-8 bg-stone-50/50">
            <div className="space-y-4">
                <div className="space-y-2">
                    <label className="text-sm font-semibold text-stone-700">What do you want to know?</label>
                    <input 
                        type="text" 
                        value={query}
                        onChange={(e) => setQuery(e.target.value)}
                        className="w-full px-4 py-3 rounded-xl border border-stone-200 focus:ring-2 focus:ring-rose-200 outline-none"
                    />
                </div>
                <button 
                    onClick={handleAnalyze}
                    disabled={!file || loading}
                    className="w-full bg-stone-800 hover:bg-stone-900 text-white font-medium py-3.5 rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    {loading ? <Loader2 className="animate-spin" /> : <Camera size={20} />}
                    {loading ? "Analyzing..." : "Analyze Look"}
                </button>
            </div>
        </div>
      </div>

      {/* Result Display */}
      {analysis && (
        <div className="bg-white p-6 md:p-8 rounded-2xl shadow-md border-l-4 border-rose-400 animate-in slide-in-from-bottom-2 fade-in">
            <h3 className="font-serif font-bold text-xl text-stone-800 mb-3 flex items-center gap-2">
                <Sparkles size={20} className="text-rose-500" />
                Stylist's Verdict
            </h3>
            <div className="prose prose-stone text-stone-600 leading-relaxed whitespace-pre-wrap">
                {analysis}
            </div>
        </div>
      )}
    </div>
  );
};

export default OutfitAnalyzer;

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { MessageCircle, Send, Loader2, User, Sparkles } from 'lucide-react';
import { ChatMessage } from '../types';

const ChatInterface: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Hello! I am your personal Hijab stylist. Ask me about trends, fabric care, or styling tips!' }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Use a ref to persist the chat session across renders, but initialize appropriately
  const chatSessionRef = useRef<any>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const initChat = () => {
      const apiKey = process.env.API_KEY;
      if (!apiKey) return;
      const ai = new GoogleGenAI({ apiKey });
      chatSessionRef.current = ai.chats.create({
          model: 'gemini-3-flash-preview',
          config: {
              systemInstruction: "You are a friendly, knowledgeable Hijab fashion expert. You provide advice on modest fashion, color theory, fabric choices, and latest hijab trends. Keep answers concise, helpful, and polite."
          }
      });
  };

  useEffect(() => {
      if (!chatSessionRef.current) {
          initChat();
      }
  }, []);

  const handleSend = async () => {
    if (!input.trim() || !chatSessionRef.current) return;

    const userMsg: ChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      const result = await chatSessionRef.current.sendMessage({ message: userMsg.text });
      const modelMsg: ChatMessage = { role: 'model', text: result.text || "I couldn't quite get that." };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Sorry, I'm having trouble connecting to the styling service right now." }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto h-[calc(100vh-140px)] md:h-[600px] flex flex-col bg-white rounded-2xl shadow-sm border border-stone-200 overflow-hidden">
      <header className="p-4 border-b border-stone-100 bg-stone-50/50 flex items-center gap-3">
        <div className="bg-rose-100 p-2 rounded-full text-rose-600">
            <MessageCircle size={20} />
        </div>
        <div>
            <h3 className="font-serif font-bold text-stone-800">Fashion Chat</h3>
            <p className="text-xs text-stone-500">Ask about trends & tips</p>
        </div>
      </header>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-stone-50/30">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex max-w-[80%] gap-2 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${msg.role === 'user' ? 'bg-stone-800 text-white' : 'bg-rose-100 text-rose-600'}`}>
                    {msg.role === 'user' ? <User size={14} /> : <Sparkles size={14} />}
                </div>
                <div className={`p-3 rounded-2xl text-sm leading-relaxed shadow-sm ${
                    msg.role === 'user' 
                    ? 'bg-stone-800 text-white rounded-tr-none' 
                    : 'bg-white text-stone-700 border border-stone-100 rounded-tl-none'
                }`}>
                    {msg.text}
                </div>
            </div>
          </div>
        ))}
        {loading && (
             <div className="flex justify-start">
             <div className="flex max-w-[80%] gap-2 flex-row">
                 <div className="w-8 h-8 rounded-full flex items-center justify-center shrink-0 bg-rose-100 text-rose-600">
                     <Sparkles size={14} />
                 </div>
                 <div className="bg-white p-3 rounded-2xl rounded-tl-none border border-stone-100 shadow-sm">
                     <Loader2 size={16} className="animate-spin text-stone-400" />
                 </div>
             </div>
           </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 border-t border-stone-100 bg-white">
        <form 
            onSubmit={(e) => { e.preventDefault(); handleSend(); }}
            className="flex gap-2"
        >
            <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Type your fashion question..."
                className="flex-1 px-4 py-3 rounded-xl border border-stone-200 focus:ring-2 focus:ring-rose-200 outline-none bg-stone-50 focus:bg-white transition-all"
            />
            <button 
                type="submit"
                disabled={!input.trim() || loading}
