import { GoogleGenAI, Type } from "@google/genai";
import { GeneratedLook, StylingPreferences } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to convert File to Base64
export const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];
      resolve({
        inlineData: {
          data: base64Data,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Generates a text styling advice and a prompt for image generation.
 */
export const generateStylingAdvice = async (prefs: StylingPreferences): Promise<GeneratedLook> => {
  const ai = getClient();

  const prompt = `
    Act as a professional Muslimah fashion stylist. Create a complete outfit recommendation based on:
    - Occasion: ${prefs.occasion}
    - Style: ${prefs.style}
    - Color Palette: ${prefs.colors}
    - Preferred Hijab Type: ${prefs.hijabType}

    Output valid JSON with the following structure:
    {
      "description": "A vivid, inspiring description of the outfit.",
      "tips": ["Tip 1", "Tip 2", "Tip 3"],
      "items": ["Item 1", "Item 2", "Item 3", "Item 4"],
      "imagePrompt": "A highly detailed prompt to generate a photorealistic image of this outfit worn by a model with a hijab, ensuring modesty and style."
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
            type: Type.OBJECT,
            properties: {
                description: { type: Type.STRING },
                tips: { type: Type.ARRAY, items: { type: Type.STRING } },
                items: { type: Type.ARRAY, items: { type: Type.STRING } },
                imagePrompt: { type: Type.STRING }
            }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from Stylist AI");

    const data = JSON.parse(text);
    return data;

  } catch (error) {
    console.error("Error generating styling advice:", error);
    throw error;
  }
};

/**
 * Generates an image of the outfit based on a description.
 */
export const generateOutfitImage = async (imagePrompt: string): Promise<string | undefined> => {
    const ai = getClient();
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [{ text: imagePrompt + ", high quality, photorealistic, fashion photography, 8k, modest fashion" }]
            },
            config: {
                imageConfig: {
                    aspectRatio: "3:4"
                }
            }
        });

        // Extract image
        for (const part of response.candidates?.[0]?.content?.parts || []) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        return undefined;
    } catch (error) {
        console.error("Error generating image:", error);
        return undefined; // Fail gracefully for image
    }
};

/**
 * Modifies the outfit in the provided image based on the prompt (Virtual Try-On).
 */
export const generateVirtualTryOn = async (file: File, prompt: string): Promise<string | undefined> => {
    const ai = getClient();
    const imagePart = await fileToGenerativePart(file);

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [
                    imagePart,
                    { text: `Edit this image. Swap the person's current outfit with the following style: ${prompt}. Ensure the hijab style matches the description. Keep the person's pose, face, and background consistent.` }
                ]
            }
        });

        // Extract image
        for (const part of response.candidates?.[0]?.content?.parts || []) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        return undefined;
    } catch (error) {
        console.error("Error generating virtual try-on:", error);
        return undefined;
    }
};

/**
 * Analyzes an uploaded photo and provides advice.
 */
export const analyzeUploadedLook = async (file: File, query: string): Promise<string> => {
    const ai = getClient();
    const imagePart = await fileToGenerativePart(file);

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    imagePart,
                    { text: `You are a Hijab fashion stylist. Analyze this image. User question: "${query}". Provide specific, helpful advice on color matching, style improvement, or hijab styling. Be encouraging and polite.` }
                ]
            }
        });

        return response.text || "I couldn't analyze the image clearly. Please try again.";
    } catch (error) {
        console.error("Error analyzing look:", error);
        throw error;
    }
};

