import { GoogleGenAI, Type } from "@google/genai";
import { GeneratedLook, StylingPreferences } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to convert File to Base64
export const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];
      resolve({
        inlineData: {
          data: base64Data,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Generates an image of the outfit based on a description (Text-to-Image).
 */
export const generateOutfitImage = async (imagePrompt: string): Promise<string | undefined> => {
    const ai = getClient();
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [{ text: imagePrompt + ", high quality, photorealistic, fashion photography, 8k, modest fashion, beautiful lighting" }]
            },
            config: {
                imageConfig: {
                    aspectRatio: "3:4"
                }
            }
        });

        for (const part of response.candidates?.[0]?.content?.parts || []) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        return undefined;
    } catch (error) {
        console.error("Error generating image:", error);
        return undefined;
    }
};

/**
 * Modifies the uploaded image based on the specific mode and prompt.
 */
export const generateVirtualTryOn = async (
    modelFile: File, 
    prompt: string, 
    referenceFile: File | null,
    creativityLevel: number = 50,
    mode: 'outfit' | 'bg' | 'pose' = 'outfit'
): Promise<string | undefined> => {
    const ai = getClient();
    const modelPart = await fileToGenerativePart(modelFile);

    const parts: any[] = [modelPart];

    // Base instruction context
    let instructions = "";

    // Specific Prompt Engineering based on Mode
    if (mode === 'outfit') {
        instructions = `Edit this image to change the person's OUTFIT only. 
        Maintain the face, body shape, and background strictly.
        The new outfit should match this description: "${prompt}".`;

        if (referenceFile) {
            const refPart = await fileToGenerativePart(referenceFile);
            parts.push(refPart);
            instructions += ` Use the second image provided as a STRICT VISUAL REFERENCE for the clothing texture, color, and style. Transfer the style from the reference image to the person in the first image.`;
        }
    } 
    else if (mode === 'bg') {
        instructions = `Edit this image to change the BACKGROUND only. 
        Keep the person (face, body, and current outfit) exactly as they are. 
        Remove the current background and replace it with: "${prompt}". 
        Ensure lighting on the person matches the new background.`;
    } 
    else if (mode === 'pose') {
        instructions = `Generate a new image of the person in the first image, but change their POSE.
        Target Pose: "${prompt}".
        Maintain the person's identity (face, hijab style) and their current outfit as closely as possible. 
        The result must be photorealistic.`;
    }

    instructions += `
    Creativity/Freedom Level: ${creativityLevel}%. 
    (Lower creativity = strict adherence to original image/reference. Higher creativity = more artistic freedom).
    Ensure the final result is 8k resolution, photorealistic, and maintains modesty suitable for Hijab fashion context.`;

    parts.push({ text: instructions });

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts },
        });

        for (const part of response.candidates?.[0]?.content?.parts || []) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        return undefined;
    } catch (error) {
        console.error("Error generating virtual try-on:", error);
        throw error;
    }
};

/**
 * Analyzes an uploaded outfit image to provide styling advice.
 */
export const analyzeUploadedLook = async (file: File, query: string): Promise<string> => {
  const ai = getClient();
  const imagePart = await fileToGenerativePart(file);

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [imagePart, { text: query }]
      },
      config: {
        systemInstruction: "You are a friendly, knowledgeable Hijab fashion expert. You provide advice on modest fashion, color theory, fabric choices, and latest hijab trends. Keep answers concise, helpful, and polite."
      }
    });

    return response.text || "Could not analyze the image.";
  } catch (error) {
    console.error("Error analyzing uploaded look:", error);
    throw error;
  }
};

