import { Loader2, Sparkles, Download, Upload, X, Shirt, Image as ImageIcon, User, Wand2, RefreshCw } from 'lucide-react';

// Data Categories for each mode
const OUTFIT_CATEGORIES = {
  Gaya: ['Casual', 'Formal Kantor', 'Syar\'i Modern', 'Street Style', 'Vintage', 'Korean Look', 'Minimalist'],
  Atasan: ['Kemeja Oversized', 'Blouse Ruffle', 'Tunik Panjang', 'Sweater Rajut', 'Blazer', 'T-shirt', 'Cardigan', 'Outer Kimono'],
  Bawahan: ['Rok Plisket', 'Kulot Highwaist', 'Jeans Loose', 'Rok A-Line', 'Celana Bahan', 'Rok Span', 'Celana Cargo'],
  Hijab: ['Pashmina Plisket', 'Segi Empat Paris', 'Bergo Sport', 'Turban', 'Pashmina Silk', 'Syar\'i Layer', 'Scarf Pattern']
};

const BG_CATEGORIES = {
  Lokasi: ['Cafe Aesthetic', 'Taman Bunga', 'Pantai Sunset', 'City Street', 'Studio Minimalis', 'Perpustakaan', 'Pegunungan'],
  Suasana: ['Cerah (Daylight)', 'Golden Hour', 'Malam Kota (City Lights)', 'Mendung Dramatis', 'Indoor Warm', 'Studio White']
};

const POSE_CATEGORIES = {
  Tipe: ['Berdiri Candid', 'Duduk Santai', 'Walking Shot', 'Selfie Mirror', 'Close Up', 'Back View (Menoleh)'],
  Ekspresi: ['Senyum Natural', 'Fierce/Model', 'Tertawa', 'Melihat ke samping', 'Mata tertutup estetik']
};

const StyleGenerator: React.FC = () => {
  // State for Inputs
  const [modelPhoto, setModelPhoto] = useState<File | null>(null);
  const [modelPreview, setModelPreview] = useState<string | null>(null);
  const [refPhoto, setRefPhoto] = useState<File | null>(null);
  const [refPreview, setRefPreview] = useState<string | null>(null);
  const [creativity, setCreativity] = useState(50);
  const [activeTab, setActiveTab] = useState<'outfit' | 'bg' | 'pose'>('outfit');

  // Dynamic Selections based on active tab
  const [outfitSel, setOutfitSel] = useState<Record<string, string>>({});
  const [bgSel, setBgSel] = useState<Record<string, string>>({});
  const [poseSel, setPoseSel] = useState<Record<string, string>>({});

  // Additional prompt
  const [customPrompt, setCustomPrompt] = useState("");

  // State for Generation
  const [loading, setLoading] = useState(false);
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Refs for file inputs
  const modelInputRef = useRef<HTMLInputElement>(null);
  const refInputRef = useRef<HTMLInputElement>(null);

  // Reset result when changing core inputs
  useEffect(() => {
     setResultImage(null);
  }, [activeTab, modelPhoto]);

  // Handlers
  const handleModelUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      const file = e.target.files[0];
      setModelPhoto(file);
      setModelPreview(URL.createObjectURL(file));
      setResultImage(null);
    }
