    try {
        let url;
        if (modelPhoto) {
             // Pass activeTab as the mode to the API
             url = await generateVirtualTryOn(modelPhoto, prompt, refPhoto, creativity, activeTab);
        } else {
             // Fallback: Text to Image (Only sensible for Outfit mode usually)
             if (activeTab !== 'outfit') {
                 setError("Upload foto terlebih dahulu untuk mengganti Background atau Pose.");
                 setLoading(false);
                 return;
             }
             prompt += ". Full body shot of a muslimah model, photorealistic, 8k.";
             url = await generateOutfitImage(prompt);
        }

        if (url) {
            setResultImage(url);
        } else {
            setError("Gagal menghasilkan gambar. Coba kurangi tingkat kreativitas atau ubah deskripsi.");
        }
    } catch (err) {
        setError("Something went wrong. Please check your connection.");
    } finally {
        setLoading(false);
    }
  };

