  );
};

export default StyleGenerator;

import { GoogleGenAI, Type } from "@google/genai";
import { GeneratedLook, StylingPreferences } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to convert File to Base64
export const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];
      resolve({
        inlineData: {
          data: base64Data,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Generates an image of the outfit based on a description.
 */
export const generateOutfitImage = async (imagePrompt: string): Promise<string> => {
    const ai = getClient();
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [{ text: imagePrompt + ", high quality, photorealistic, fashion photography, 8k, modest fashion" }]
            },
            config: {
                imageConfig: {
                    aspectRatio: "3:4"
                }
            }
        });

        // Extract image
        for (const part of response.candidates?.[0]?.content?.parts || []) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }

        const candidate = response.candidates?.[0];
        if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
            throw new Error(`AI Safety Block: ${candidate.finishReason}`);
        }

        throw new Error("No image generated.");
    } catch (error) {
        console.error("Error generating image:", error);
        throw error;
    }
};

/**
 * Modifies the image based on the specific mode (outfit, bg, pose).
 */
export const generateVirtualTryOn = async (
    modelFile: File, 
    prompt: string, 
    referenceFile: File | null,
    creativityLevel: number = 50,
    mode: 'outfit' | 'bg' | 'pose' = 'outfit'
): Promise<string> => {
    const ai = getClient();
    const modelPart = await fileToGenerativePart(modelFile);

    const parts: any[] = [modelPart];

    // Base instruction depending on mode
    let instructions = "";

    if (mode === 'outfit') {
        instructions = `Edit this image to change the PERSON'S OUTFIT only. 
        Keep the face, body shape, and background exactly as they are.
        Target Outfit: ${prompt}.`;

        if (referenceFile) {
            const refPart = await fileToGenerativePart(referenceFile);
            parts.push(refPart);
            instructions += ` Use the second image as a STRICT VISUAL REFERENCE for the style, texture, and color of the new outfit. Transfer the style.`;
        }
    } else if (mode === 'bg') {
        instructions = `Edit this image to change the BACKGROUND only.
        Keep the person (face, body, and current outfit) exactly as they are.
        Remove the current background and replace it with: ${prompt}.
        Ensure realistic lighting blending on the person.`;
    } else if (mode === 'pose') {
        instructions = `Regenerate the person in the image with a NEW POSE.
        Target Pose: ${prompt}.
        Keep the person's identity (face, hijab) and their current outfit as closely as possible. 
        Only change how they are standing/sitting.`;
    }

    instructions += `
    Creativity Level: ${creativityLevel}%. 
    Ensure the result is high quality, photorealistic, 8k resolution, and suitable for Hijab fashion.`;

    parts.push({ text: instructions });

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts },
        });

        // Extract image
        for (const part of response.candidates?.[0]?.content?.parts || []) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }

        const candidate = response.candidates?.[0];
        if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
             throw new Error(`AI Safety Block: ${candidate.finishReason}`);
        }

        throw new Error("No image generated.");
    } catch (error) {
        console.error("Error generating virtual try-on:", error);
        throw error;
    }
};

/**
 * Analyzes an uploaded photo and provides advice.
 */
export const analyzeUploadedLook = async (file: File, query: string): Promise<string> => {
    const ai = getClient();
    const imagePart = await fileToGenerativePart(file);

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    imagePart,
                    { text: `You are a Hijab fashion stylist. Analyze this image. User question: "${query}". Provide specific, helpful advice on color matching, style improvement, or hijab styling. Be encouraging and polite.` }
                ]
            }
        });

        if (!response.text) {
             throw new Error("No analysis text returned.");
        }
        return response.text;
    } catch (error) {
        console.error("Error analyzing look:", error);
        throw error;
    }
};

