        }
    } catch (err: any) {
        console.error("Generation Error:", err);

        let displayError = "Terjadi kesalahan saat memproses permintaan Anda.";
        const msg = (err.message || err.toString()).toLowerCase();

        if (msg.includes('401') || msg.includes('api key')) {
            displayError = "Akses ditolak: API Key tidak valid atau tidak ditemukan.";
        } else if (msg.includes('403')) {
            displayError = "Akses ditolak: Lokasi atau akun tidak diizinkan.";
        } else if (msg.includes('429') || msg.includes('quota') || msg.includes('exhausted')) {
            displayError = "Kuota API harian habis. Silakan coba lagi besok.";
        } else if (msg.includes('500') || msg.includes('503') || msg.includes('overloaded')) {
             displayError = "Server Google AI sedang sibuk. Mohon tunggu sejenak.";
        } else if (msg.includes('safety') || msg.includes('blocked') || msg.includes('finishreason')) {
             displayError = "Gambar tidak dapat dibuat karena melanggar kebijakan keamanan konten.";
        } else if (msg.includes('network') || msg.includes('failed to fetch')) {
             displayError = "Gagal terhubung ke internet. Periksa koneksi Anda.";
        } else if (msg.includes('no content returned') || msg.includes('no image generated')) {
             displayError = "AI tidak menghasilkan gambar. Coba ubah deskripsi atau prompt.";
        }

        setError(displayError);
    } finally {
        setLoading(false);
    }
