import { GoogleGenAI, Type } from "@google/genai";
import { GeneratedLook, StylingPreferences } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to convert File to Base64
export const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1];
      resolve({
        inlineData: {
          data: base64Data,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Generates an image of the outfit based on a description.
 */
export const generateOutfitImage = async (imagePrompt: string, aspectRatio: string = "3:4"): Promise<string> => {
    const ai = getClient();
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [{ text: imagePrompt + ", high quality, photorealistic, fashion photography, 8k, modest fashion" }]
            },
            config: {
                imageConfig: {
                    aspectRatio: aspectRatio
                }
            }
        });

        // Extract image
        for (const part of response.candidates?.[0]?.content?.parts || []) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }

        const candidate = response.candidates?.[0];
        if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
            throw new Error(`AI Safety Block: ${candidate.finishReason}`);
        }

        throw new Error("No image generated.");
    } catch (error) {
        console.error("Error generating image:", error);
        throw error;
    }
};

/**
 * Modifies the image based on the specific mode (outfit, bg, pose).
 */
export const generateVirtualTryOn = async (
    modelFile: File, 
    prompt: string, 
    referenceFile: File | null,
    creativityLevel: number = 50,
    mode: 'outfit' | 'bg' | 'pose' = 'outfit',
    aspectRatio: string = "3:4"
): Promise<string> => {
    const ai = getClient();
    const modelPart = await fileToGenerativePart(modelFile);

    const parts: any[] = [modelPart];

    // Map creativity (0-100) to temperature (0.0 - 1.0)
    // Lower temperature = More adherence to the prompt and source image logic
    const temperature = Math.max(0.1, Math.min(1.0, creativityLevel / 100));

    // Base instruction depending on mode
    let instructions = "";

    if (mode === 'outfit') {
        instructions = `You are a professional fashion photo retoucher.
        TASK: Replace the outfit in the image with: "${prompt}".

        CRITICAL RULES FOR FACE PRESERVATION:
        1. DO NOT change the face, facial features, makeup, or skin tone.
        2. DO NOT change the body shape or head size.
        3. The face MUST remain 100% identical to the original photo.
        4. Blend the new outfit naturally at the neck and wrist lines.
        5. Keep the original background exactly as it is.

        Focus strictly on inpainting the clothing area only.`;

        if (referenceFile) {
            const refPart = await fileToGenerativePart(referenceFile);
            parts.push(refPart);
            instructions += `\nVISUAL REFERENCE: Use the second image as a STYLE SOURCE for the new outfit (texture, color, pattern). Transfer this style to the person in the first image.`;
        }
    } else if (mode === 'bg') {
        instructions = `You are an expert compositor.
        TASK: Change the background of this image to: "${prompt}".

        CRITICAL RULES:
        1. PRESERVE THE PERSON EXACTLY. Do not change their face, expression, or outfit.
        2. Perform precise segmentation of the person.
        3. Replace ONLY the background pixels.
        4. Adjust the lighting on the person slightly to match the new environment, but do not alter their identity.`;

        if (referenceFile) {
            const refPart = await fileToGenerativePart(referenceFile);
            parts.push(refPart);
            instructions += `\nBACKGROUND SOURCE: Use the second image as the new background. Composite the person from the first image into this scene naturally.`;
        } else {
            instructions += `\nGenerate a photorealistic background based on the text description.`;
        }
    } else if (mode === 'pose') {
        instructions = `TASK: Regenerate the person with a NEW POSE: "${prompt}".

        CRITICAL RULES:
        1. You MUST preserve the facial identity (eyes, nose, mouth, face shape) of the original person.
        2. Keep the same outfit style and hijab style.
        3. The result must look like the SAME PERSON, just moving.
        4. Photorealistic, 8k quality.`;
    }

    instructions += `\n\nEnsure high quality, realistic textures. Maintain the modest fashion aesthetic.`;

    parts.push({ text: instructions });

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts },
            config: {
                // Using temperature to control how much "hallucination" is allowed.
                temperature: temperature,
                imageConfig: {
                    aspectRatio: aspectRatio
                }
            }
        });

        // Extract image
        for (const part of response.candidates?.[0]?.content?.parts || []) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }

        const candidate = response.candidates?.[0];
        if (candidate?.finishReason && candidate.finishReason !== 'STOP') {
             throw new Error(`AI Safety Block: ${candidate.finishReason}`);
        }

        throw new Error("No image generated.");
    } catch (error) {
        console.error("Error generating virtual try-on:", error);
        throw error;
    }
};

/**
 * Analyzes an uploaded photo and provides advice.
