     setResultImage(null);
  }, [modelPhoto]);

  // Reset zoom/pan when result changes
  useEffect(() => {
    setZoom(1);
    setPan({ x: 0, y: 0 });
  }, [resultImage]);

  // Clear reference when switching tabs to avoid confusion
  useEffect(() => {
      setRefPhoto(null);
      setRefPreview(null);
  }, [activeTab]);

