      setRefPhoto(null);
      setRefPreview(null);
  }, [activeTab]);

  // Handlers
  const handleModelUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      const file = e.target.files[0];
      setModelPhoto(file);
      setModelPreview(URL.createObjectURL(file));
      setResultImage(null);
    }
  };

  const handleRefUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      const file = e.target.files[0];
      setRefPhoto(file);
      setRefPreview(URL.createObjectURL(file));
    }
  };

  const handleResetResult = () => {
      setResultImage(null);
  };

  const toggleSelection = (category: string, item: string) => {
    const setSel = activeTab === 'outfit' ? setOutfitSel 
                 : activeTab === 'bg' ? setBgSel 
                 : setPoseSel;

    setSel(prev => ({
      ...prev,
      [category]: prev[category] === item ? '' : item
    }));
  };

  const randomizeSelections = () => {
    let categories: any = {};
    let setSel: any = null;

    if (activeTab === 'outfit') { categories = OUTFIT_CATEGORIES; setSel = setOutfitSel; }
    else if (activeTab === 'bg') { categories = BG_CATEGORIES; setSel = setBgSel; }
    else { categories = POSE_CATEGORIES; setSel = setPoseSel; }

    const newSel: any = {};
    Object.keys(categories).forEach(cat => {
      const items = categories[cat];
      newSel[cat] = items[Math.floor(Math.random() * items.length)];
    });
    setSel(newSel);
  };

  const handleAIRecommendation = async () => {
      if (!modelPhoto) {
          setError("Silakan upload foto terlebih dahulu agar AI bisa menganalisis.");
          return;
      }

      setAnalyzing(true);
      setError(null);
      try {
          const promptRecommendation = await getOutfitRecommendations(modelPhoto);
          setCustomPrompt(promptRecommendation);
          // Clear manual selections to give full control to the AI prompt
          setOutfitSel({});
      } catch (err) {
          console.error("Analysis Failed", err);
          setError("Gagal mendapatkan rekomendasi AI. Silakan coba lagi.");
      } finally {
          setAnalyzing(false);
      }
  };

  const getActiveSelections = () => {
    if (activeTab === 'outfit') return outfitSel;
    if (activeTab === 'bg') return bgSel;
    return poseSel;
  };

  const getActiveCategories = () => {
    if (activeTab === 'outfit') return OUTFIT_CATEGORIES;
    if (activeTab === 'bg') return BG_CATEGORIES;
    return POSE_CATEGORIES;
  };

  // Helper to get progress message
  const getProgressMessage = () => {
      if (progress < 30) {
          if (activeTab === 'outfit') return "Menganalisis bentuk tubuh & hijab...";
          if (activeTab === 'bg') return "Memisahkan subjek dari background...";
          if (activeTab === 'pose') return "Mendeteksi struktur tulang...";
          return "Memulai proses...";
      } else if (progress < 70) {
          if (activeTab === 'outfit') return "Menjahit outfit baru secara digital...";
          if (activeTab === 'bg') return "Membangun lingkungan baru...";
          if (activeTab === 'pose') return "Menggenerasi pose baru...";
          return "Menggenerasi gambar...";
      } else {
          if (activeTab === 'outfit') return "Menyesuaikan tekstur kain & cahaya...";
          if (activeTab === 'bg') return "Blending cahaya & bayangan...";
          if (activeTab === 'pose') return "Menjaga kemiripan wajah...";
          return "Finishing sentuhan akhir...";
      }
  };

  const handleGenerate = async () => {
    setLoading(true);
    setProgress(0);
    setError(null);

    // Start progress simulation
    progressInterval.current = setInterval(() => {
        setProgress((prev) => {
            if (prev >= 90) return 90; // Hold at 90% until done
            // Slower increment as it gets higher
            const increment = prev < 50 ? 5 : 1; 
            return prev + increment;
        });
    }, 300);

    // Construct prompt
    const selections = getActiveSelections();
    let prompt = "";

    if (activeTab === 'outfit') {
        const style = selections['Gaya'];
        const top = selections['Atasan'];
        const bottom = selections['Bawahan'];
        const hijab = selections['Hijab'];

        // 1. Build Base Context
        let description = "Seorang model fashion muslimah";
        if (style) {
            description += ` dengan gaya ${style}`;
        } else {
            description += " dengan gaya OOTD modern";
        }

        // 2. Add Specific Items
        const clothingItems = [];
        if (hijab) clothingItems.push(`memakai hijab model ${hijab}`);
        if (top) clothingItems.push(`mengenakan atasan ${top}`);
        if (bottom) clothingItems.push(`bawahan ${bottom}`);

        if (clothingItems.length > 0) {
            description += `, ${clothingItems.join(', ')}`;
        }

        // 3. Combine with Custom Prompt & Aesthetics
        if (customPrompt) {
            // If user provided a specific prompt, append it
             description += `. Detail tambahan: ${customPrompt}`;
        } else {
            // If custom prompt is empty, add descriptive enhancers to ensure high quality
             description += ". Tampilan fotogenik, pencahayaan studio yang lembut, tekstur kain detail, resolusi tinggi 8k, warna yang harmonis.";
        }

        prompt = description;
    } else {
        const descriptionParts = Object.entries(selections)
          .filter(([_, val]) => val)
          .map(([key, val]) => `${key}: ${val}`);

        if (customPrompt) descriptionParts.push(customPrompt);
        prompt = descriptionParts.join(', ');
    }

    // Fallback if prompt is still empty (e.g. user cleared everything)
    if (!prompt && !refPhoto) {
         if (activeTab === 'outfit') prompt = "Full body shot of a stylish muslimah model wearing trending hijab outfit, photorealistic, 8k, highly detailed";
         else if (activeTab === 'bg') prompt = "Beautiful aesthetic background, high quality";
         else prompt = "Model posing naturally, photorealistic";
    }

    try {
        let url;
        let sourceImageFile = modelPhoto;

        // CHAINING LOGIC:
        if (resultImage) {
            try {
                sourceImageFile = await base64ToFile(resultImage, "edited_image.png");
            } catch (e) {
                console.warn("Failed to reuse result image, falling back to original", e);
                sourceImageFile = modelPhoto;
            }
        }

        if (sourceImageFile) {
             url = await generateVirtualTryOn(sourceImageFile, prompt, refPhoto, creativity, activeTab, aspectRatio, faceLock);
        } else {
             // Fallback: Text to Image
             if (activeTab !== 'outfit') {
                 setError("Upload foto terlebih dahulu untuk mengganti Background atau Pose.");
                 setLoading(false);
                 if (progressInterval.current) clearInterval(progressInterval.current);
                 return;
             }
             prompt += ". Full body shot of a muslimah model, photorealistic, 8k.";
             url = await generateOutfitImage(prompt, aspectRatio);
        }

        if (url) {
            setResultImage(url);
        }
    } catch (err: any) {
        console.error("Generation Error:", err);

        let displayError = "Terjadi kesalahan saat memproses permintaan Anda.";
        const msg = (err.message || err.toString()).toLowerCase();

        if (msg.includes('401') || msg.includes('api key')) {
            displayError = "Akses ditolak: API Key tidak valid atau tidak ditemukan.";
        } else if (msg.includes('safety') || msg.includes('blocked')) {
             displayError = "Gambar tidak dapat dibuat karena melanggar kebijakan keamanan konten.";
        }

        setError(displayError);
    } finally {
        if (progressInterval.current) clearInterval(progressInterval.current);
        setProgress(100);
        setTimeout(() => setLoading(false), 600); // Slight delay to show 100% completion
    }
  };

  // Zoom Handlers
  const handleZoomIn = (e: React.MouseEvent) => {
    e.stopPropagation();
    setZoom(z => Math.min(z + 0.5, 4));
  };
  const handleZoomOut = (e: React.MouseEvent) => {
    e.stopPropagation();
    setZoom(z => {
      const newZoom = Math.max(z - 0.5, 1);
      if (newZoom === 1) setPan({ x: 0, y: 0 });
      return newZoom;
    });
  };
  const handleResetZoom = (e: React.MouseEvent) => {
    e.stopPropagation();
    setZoom(1); 
    setPan({x:0,y:0});
  };

  // Pan Handlers
  const handlePanStart = (e: React.MouseEvent | React.TouchEvent) => {
    if (zoom > 1) {
      setIsDragging(true);
      const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
      const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
      setDragStart({ x: clientX - pan.x, y: clientY - pan.y });
    }
  };

  const handlePanMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (isDragging && zoom > 1) {
      e.preventDefault(); // Prevent default scroll on mobile when panning
      const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
      const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
      setPan({
        x: clientX - dragStart.x,
        y: clientY - dragStart.y
      });
    }
  };

  const handlePanEnd = () => setIsDragging(false);


  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-in fade-in duration-500 pb-12">
      {/* Header */}
      <div className="text-center space-y-2 mb-8">
        <h1 className="text-3xl md:text-5xl font-serif font-bold text-stone-900">
          Al Hijab <span className="text-transparent bg-clip-text bg-gradient-to-r from-rose-500 to-purple-600">Magic Studio</span>
        </h1>
        <p className="text-stone-500 text-sm md:text-base">
          Virtual Makeover: Ganti gaya hijab, outfit, background, atau pose dengan AI
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* LEFT COLUMN - CONTROLS */}
        <div className="lg:col-span-5 space-y-6">

          {/* 1. FOTO EDITOR */}
          <div className="bg-white p-5 rounded-3xl shadow-sm border border-stone-100">
            <div className="flex items-center gap-2 mb-4">
              <div className="bg-rose-500 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">1</div>
              <h3 className="font-bold text-stone-800 tracking-wide text-sm">FOTO & MODE</h3>
            </div>

            {/* Main Upload Area */}
            <div className="mb-4">
              {!modelPreview ? (
                <div 
                  onClick={() => modelInputRef.current?.click()}
                  className="h-64 border-2 border-dashed border-stone-300 rounded-2xl flex flex-col items-center justify-center cursor-pointer hover:bg-stone-50 transition-all group"
                >
                  <div className="bg-rose-50 p-3 rounded-full mb-3 group-hover:bg-rose-100 transition-colors">
                    <Upload size={24} className="text-rose-500" />
                  </div>
                  <span className="text-stone-600 font-medium text-sm">Upload Foto OOTD</span>
                  <span className="text-stone-400 text-xs mt-1">Format JPG, PNG (Max 5MB)</span>
                </div>
              ) : (
                <div className="relative h-64 rounded-2xl overflow-hidden bg-stone-100 border border-stone-200 group">
                  <img src={modelPreview} alt="Model" className="w-full h-full object-cover" />

                  {/* Face Lock Overlay Button */}
                  <div className="absolute top-2 left-2 z-10">
                      <button
                          onClick={(e) => { e.stopPropagation(); setFaceLock(!faceLock); }}
                          className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[10px] font-bold backdrop-blur-md border transition-all ${
                              faceLock
                              ? 'bg-rose-500/90 border-rose-400 text-white shadow-lg shadow-rose-900/20'
                              : 'bg-white/80 border-white/50 text-stone-500 hover:bg-white'
                          }`}
                          title={faceLock ? "Wajah dikunci: AI tidak akan mengubah fitur wajah" : "Wajah tidak dikunci: AI bebas berkreasi"}
                      >
                          {faceLock ? <Lock size={12} /> : <Unlock size={12} />}
                          {faceLock ? 'Wajah Terkunci' : 'Wajah Tidak Terkunci'}
                      </button>
                  </div>

                  <button 
                    onClick={() => { setModelPhoto(null); setModelPreview(null); }}
                    className="absolute top-2 right-2 bg-black/50 hover:bg-black/70 text-white p-1.5 rounded-full transition-all"
                  >
                    <X size={16} />
                  </button>
                  <div className="absolute bottom-2 left-2 bg-black/50 px-2 py-1 rounded text-[10px] text-white">
                     Foto Asli
                  </div>
                </div>
              )}
              <input ref={modelInputRef} type="file" accept="image/*" onChange={handleModelUpload} className="hidden" />
            </div>

            {/* Aspect Ratio Selection */}
            <div className="mb-6">
                <span className="text-xs font-bold text-stone-400 uppercase tracking-wider block mb-2">Ukuran Foto</span>
                <div className="grid grid-cols-5 gap-2">
                    {ASPECT_RATIOS.map((ratio) => (
                        <button
                            key={ratio.value}
                            onClick={() => setAspectRatio(ratio.value)}
                            className={`flex flex-col items-center justify-center p-2 rounded-lg border text-[10px] font-medium transition-all ${
                                aspectRatio === ratio.value
                                ? 'bg-stone-800 text-white border-stone-800'
                                : 'bg-white text-stone-500 border-stone-200 hover:bg-stone-50'
                            }`}
                        >
                            <ratio.Icon size={16} className={`mb-1 ${ratio.value === '9:16' ? 'scale-x-75' : ratio.value === '16:9' ? 'scale-y-75' : ''}`} />
                            {ratio.label}
                        </button>
                    ))}
                </div>
            </div>

            {/* Tabs */}
            <div className="grid grid-cols-3 gap-2 mb-6">
              {[
                { id: 'outfit', label: 'Ganti Outfit', icon: Shirt },
                { id: 'bg', label: 'Ganti BG', icon: ImageIcon },
                { id: 'pose', label: 'Ganti Pose', icon: User },
              ].map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id as any)}
                  className={`flex flex-col items-center justify-center p-2 rounded-xl border transition-all ${
                    activeTab === tab.id 
                    ? 'border-rose-500 bg-rose-50 text-rose-600 font-bold shadow-sm' 
                    : 'border-stone-100 bg-stone-50 text-stone-500 hover:bg-stone-100'
                  }`}
                >
                  <tab.icon size={18} className="mb-1" />
                  <span className="text-[10px]">{tab.label}</span>
                </button>
              ))}
            </div>

            {/* Creativity Slider */}
            <div className="bg-stone-50 p-4 rounded-xl mb-4">
              <div className="flex justify-between items-center mb-2">
                <span className="text-xs font-bold text-stone-600 uppercase tracking-wider">Tingkat Perubahan</span>
                <span className="text-xs font-bold text-rose-500 bg-rose-100 px-2 py-0.5 rounded-full">{creativity}%</span>
              </div>
              <input 
                type="range" 
                min="10" 
                max="90" 
                value={creativity} 
                onChange={(e) => setCreativity(Number(e.target.value))}
                className="w-full accent-rose-500 h-1.5 bg-stone-200 rounded-lg appearance-none cursor-pointer"
              />
              <div className="flex justify-between text-[10px] text-stone-400 mt-2 font-medium">
                <span>{faceLock ? 'Wajah Terkunci (Aman)' : 'Wajah Asli (Konservatif)'}</span>
                <span>Seimbang</span>
                <span>Kreatif</span>
              </div>
               {faceLock && (
                  <p className="text-[10px] text-rose-500 mt-2 flex items-center gap-1 font-medium">
                      <Lock size={10} /> Mode Wajah Terkunci aktif: Wajah tetap asli meski tingkat perubahan tinggi.
                  </p>
               )}
            </div>

            {/* Reference Upload (Outfit OR Background) */}
            {(activeTab === 'outfit' || activeTab === 'bg') && (
                <div className="mt-4 border-t border-stone-100 pt-4 animate-in fade-in">
                <span className="text-xs font-bold text-stone-600 uppercase tracking-wider block mb-2">
                    {activeTab === 'outfit' ? 'Referensi Outfit' : 'Referensi Background'} (Opsional)
                </span>
                {!refPreview ? (
                    <div 
                    onClick={() => refInputRef.current?.click()}
                    className="h-20 border border-dashed border-stone-300 rounded-xl flex items-center justify-center gap-3 cursor-pointer hover:bg-stone-50 transition-all"
                    >
                    <Upload size={16} className="text-stone-400" />
                    <div className="text-left">
                        <p className="text-xs font-bold text-stone-600">
                            {activeTab === 'outfit' ? 'Upload Foto Baju' : 'Upload Foto Lokasi'}
                        </p>
                        <p className="text-[10px] text-stone-400">
                            {activeTab === 'outfit' ? 'AI akan meniru baju ini' : 'AI akan pakai background ini'}
                        </p>
                    </div>
                    </div>
                ) : (
                    <div className="relative h-32 rounded-xl overflow-hidden bg-stone-100 border border-stone-200">
                    <img src={refPreview} alt="Reference" className="w-full h-full object-cover" />
                    <button 
                        onClick={() => { setRefPhoto(null); setRefPreview(null); }}
                        className="absolute top-2 right-2 bg-black/50 hover:bg-black/70 text-white p-1 rounded-full"
                    >
                        <X size={12} />
                    </button>
                    </div>
                )}
                <input ref={refInputRef} type="file" accept="image/*" onChange={handleRefUpload} className="hidden" />
                </div>
            )}
          </div>

          {/* 2. PROMPT & PILIHAN */}
          <div className="bg-white p-5 rounded-3xl shadow-sm border border-stone-100">
             <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                    <div className="bg-rose-500 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">2</div>
                    <h3 className="font-bold text-stone-800 tracking-wide text-sm">
                        {activeTab === 'outfit' ? 'DESKRIPSI OUTFIT' : activeTab === 'bg' ? 'PILIH BACKGROUND' : 'PILIH POSE'}
                    </h3>
                </div>

                <div className="flex gap-2">
                    <button 
                        onClick={randomizeSelections}
                        disabled={analyzing}
                        className="flex items-center gap-1.5 bg-purple-50 hover:bg-purple-100 hover:text-purple-700 text-purple-600 px-3 py-1.5 rounded-full text-xs font-bold transition-all disabled:opacity-50"
                    >
                        <Wand2 size={12} /> Acak
                    </button>
                </div>
            </div>

            <div className="space-y-4 mb-4">
                {Object.entries(getActiveCategories()).map(([cat, items]) => (
                    <div key={cat} className="space-y-2">
                        <label className="text-xs font-bold text-stone-400 uppercase">{cat}</label>
                        <div className="flex overflow-x-auto pb-2 gap-2 scrollbar-hide -mx-1 px-1">
                            {items.map(item => (
                                <button
                                    key={item}
                                    onClick={() => toggleSelection(cat, item)}
                                    className={`whitespace-nowrap px-3 py-1.5 rounded-lg text-xs font-medium border transition-all ${
                                        getActiveSelections()[cat] === item
                                        ? 'bg-rose-500 border-rose-500 text-white shadow-md shadow-rose-200'
                                        : 'bg-white border-stone-200 text-stone-600 hover:border-stone-300'
                                    }`}
                                >
                                    {item}
                                </button>
                            ))}
                        </div>
                    </div>
                ))}
            </div>

            {/* Custom Text Input */}
            <div className="border-t border-stone-100 pt-4">
                <div className="flex justify-between items-center mb-2">
                    <label className="text-xs font-bold text-stone-400 uppercase">Deskripsi Tambahan / Prompt AI</label>
                    {activeTab === 'outfit' && (
                        <button 
                            onClick={handleAIRecommendation}
                            disabled={analyzing || !modelPhoto}
                            className={`flex items-center gap-1.5 px-3 py-1 rounded-full text-[10px] font-bold transition-all ${
                                analyzing || !modelPhoto
                                ? 'bg-stone-100 text-stone-400 cursor-not-allowed'
                                : 'bg-rose-100 text-rose-600 hover:bg-rose-200 hover:shadow-sm'
                            }`}
                        >
                            {analyzing ? <Loader2 size={10} className="animate-spin" /> : <BrainCircuit size={10} />}
                            {analyzing ? 'Menganalisis...' : 'Rekomendasi AI'}
                        </button>
                    )}
                </div>
                <textarea 
                    value={customPrompt}
                    onChange={(e) => setCustomPrompt(e.target.value)}
                    placeholder={
                        activeTab === 'outfit' ? "Tulis manual atau klik 'Rekomendasi AI' untuk auto-generate..." :
                        activeTab === 'bg' ? "Contoh: Di depan menara Eiffel..." :
                        "Contoh: Memegang buku..."
                    }
                    className="w-full text-sm p-3 border border-stone-200 rounded-xl focus:ring-2 focus:ring-rose-200 focus:border-rose-400 outline-none resize-none h-28 bg-stone-50"
                />
            </div>
          </div>

        </div>

        {/* RIGHT COLUMN - OUTPUT */}
        <div className="lg:col-span-7 h-full">
            <div className="bg-white p-5 rounded-3xl shadow-sm border border-stone-100 h-full flex flex-col">
                <div className="flex items-center justify-between gap-2 mb-4">
                    <div className="flex items-center gap-2">
                        <div className="bg-purple-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">3</div>
                        <h3 className="font-bold text-stone-800 tracking-wide text-sm">HASIL MAKEOVER</h3>
                    </div>
                    {resultImage && (
                         <button 
                            onClick={handleResetResult}
                            className="text-xs text-stone-400 hover:text-red-500 flex items-center gap-1 transition-colors"
                         >
                            <RotateCcw size={12} /> Reset
                         </button>
                    )}
                </div>

                {/* Result Canvas */}
                <div 
                    className={`flex-1 bg-stone-900 rounded-2xl relative overflow-hidden min-h-[500px] flex items-center justify-center group ${zoom > 1 ? (isDragging ? 'cursor-grabbing' : 'cursor-grab') : ''}`}
                    onMouseDown={handlePanStart}
                    onMouseMove={handlePanMove}
                    onMouseUp={handlePanEnd}
                    onMouseLeave={handlePanEnd}
                    onTouchStart={handlePanStart}
                    onTouchMove={handlePanMove}
                    onTouchEnd={handlePanEnd}
                >
                    {resultImage ? (
                        <>
                            <div 
                                style={{ 
                                    transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
                                    transition: isDragging ? 'none' : 'transform 0.2s ease-out'
                                }}
                                className="w-full h-full flex items-center justify-center"
                            >
                                 <img src={resultImage} alt="Result" className="max-w-full max-h-full object-contain pointer-events-none select-none" />
                            </div>

                            {/* Zoom Controls */}
                            <div className="absolute top-4 right-4 flex flex-col gap-2 z-10 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                                <button 
                                    onClick={handleZoomIn} 
                                    className="bg-black/50 hover:bg-black/70 text-white p-2 rounded-lg backdrop-blur-sm transition-all" 
                                    title="Zoom In"
                                >
                                    <ZoomIn size={18} />
                                </button>
                                <button 
                                    onClick={handleZoomOut} 
                                    className="bg-black/50 hover:bg-black/70 text-white p-2 rounded-lg backdrop-blur-sm transition-all" 
                                    title="Zoom Out"
                                >
                                    <ZoomOut size={18} />
                                </button>
                                {zoom > 1 && (
                                    <button 
                                        onClick={handleResetZoom} 
                                        className="bg-black/50 hover:bg-black/70 text-white p-2 rounded-lg backdrop-blur-sm transition-all" 
                                        title="Reset View"
                                    >
                                        <Maximize size={18} />
                                    </button>
                                )}
                            </div>

                            {/* Overlay Info - Hidden when zoomed in to avoid clutter */}
                            {zoom === 1 && (
                                <div className="absolute top-4 left-4 bg-black/60 backdrop-blur-md px-3 py-1.5 rounded-lg text-white text-[10px] font-medium opacity-0 group-hover:opacity-100 transition-opacity">
                                    Hasil ini akan menjadi input untuk edit berikutnya
                                </div>
                            )}

                            {/* Bottom Controls */}
                            <div className="absolute bottom-6 right-6 flex gap-3 opacity-0 group-hover:opacity-100 transition-opacity z-10">
                                 <button 
                                    onClick={(e) => { e.stopPropagation(); handleGenerate(); }}
                                    className="bg-white/10 backdrop-blur-md border border-white/20 text-white p-3 rounded-full hover:bg-white/20 transition-all"
                                    title="Regenerate"
                                 >
                                    <RefreshCw size={20} />
                                </button>
                                <a 
                                    href={resultImage} 
                                    onClick={(e) => e.stopPropagation()}
                                    download="hijab-makeover.png" 
                                    className="bg-white text-stone-900 p-3 rounded-full hover:bg-stone-100 shadow-lg transition-all"
                                    title="Download"
                                >
                                    <Download size={20} />
                                </a>
                            </div>
                        </>
                    ) : (
                        <div className="text-center p-8 w-full max-w-md mx-auto">
                             {loading ? (
                                <div className="flex flex-col items-center gap-4 w-full">
                                    <div className="relative mb-2">
                                        <div className="w-16 h-16 border-4 border-white/10 border-t-rose-500 rounded-full animate-spin"></div>
                                        <Sparkles className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-rose-500 animate-pulse" size={20} />
                                    </div>

                                    {/* PROGRESS BAR */}
                                    <div className="w-full space-y-2">
                                        <div className="flex justify-between text-[10px] font-bold text-stone-400 uppercase tracking-wider">
                                            <span>Proses AI</span>
                                            <span>{progress}%</span>
                                        </div>
                                        <div className="w-full h-2 bg-stone-800 rounded-full overflow-hidden">
                                            <div 
                                                className="h-full bg-gradient-to-r from-rose-500 via-purple-500 to-indigo-500 transition-all duration-300 ease-out"
                                                style={{ width: `${progress}%` }}
                                            />
                                        </div>
                                        <p className="text-white text-sm font-medium animate-pulse mt-2">
                                            {getProgressMessage()}
                                        </p>
                                    </div>
                                </div>
                             ) : (
                                <div className="flex flex-col items-center gap-4 text-stone-600">
                                    <Sparkles size={48} className="text-stone-700 opacity-50" />
                                    <p className="text-stone-500">Hasil generate akan muncul di sini</p>
                                    <p className="text-stone-700 text-xs max-w-xs mx-auto opacity-50">
                                        Upload foto model dan atur {activeTab} untuk melihat keajaiban AI.
                                    </p>
                                </div>
                             )}
                        </div>
                    )}

                    {/* Generate Button (Floating or Integrated) - Only visible when not zoomed and not loading */}
                    {!loading && zoom === 1 && (
                         <div className="absolute bottom-8 left-1/2 -translate-x-1/2 w-full max-w-xs z-10">
                             <button
                                onClick={handleGenerate}
                                disabled={(!modelPhoto && !resultImage) && !Object.values(getActiveSelections()).some(v => v)}
                                className="w-full bg-gradient-to-r from-rose-500 to-purple-600 hover:from-rose-600 hover:to-purple-700 text-white font-bold py-3.5 rounded-full shadow-lg shadow-purple-900/20 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed transform hover:scale-105 active:scale-95"
                            >
                                <Wand2 size={18} />
                                {resultImage ? 'Edit Hasil Ini' : 'Generate Makeover'}
                            </button>
                         </div>
                    )}
                </div>

                {/* Status/Error Bar */}
                {error && (
                    <div className="mt-4 p-3 bg-red-50 text-red-600 text-xs rounded-xl border border-red-100 text-center animate-in slide-in-from-top-2">
                        {error}
                    </div>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

export default StyleGenerator;

import React, { useState, useRef, useEffect } from 'react';
