                            {/* Bottom Controls */}
                            <div className="absolute bottom-6 right-6 flex gap-3 opacity-0 group-hover:opacity-100 transition-opacity z-10">
                                 {/* Undo Button */}
                                 {history.length > 0 && (
                                    <button
                                        onClick={handleUndo}
