                >
                  <tab.icon size={18} className="mb-1" />
                  <span className="text-[10px]">{tab.label}</span>
                </button>
              ))}
            </div>

            {/* Creativity Slider */}
            <div className="bg-stone-50 p-4 rounded-xl mb-4">
              <div className="flex justify-between items-center mb-2">
                <span className="text-xs font-bold text-stone-600 uppercase tracking-wider">Tingkat Perubahan</span>
                <span className="text-xs font-bold text-rose-500 bg-rose-100 px-2 py-0.5 rounded-full">{creativity}%</span>
