// Helper to convert Base64 URL to File object
const base64ToFile = async (url: string, filename: string): Promise<File> => {
    const res = await fetch(url);
    const blob = await res.blob();
    return new File([blob], filename, { type: blob.type });
};

const StyleGenerator: React.FC = () => {
  // State for Inputs
  const [modelPhoto, setModelPhoto] = useState<File | null>(null);
  const [modelPreview, setModelPreview] = useState<string | null>(null);
  const [refPhoto, setRefPhoto] = useState<File | null>(null);
  const [refPreview, setRefPreview] = useState<string | null>(null);

  // Default creativity lowered to 35 for better face preservation
  const [creativity, setCreativity] = useState(35);
  const [activeTab, setActiveTab] = useState<'outfit' | 'bg' | 'pose'>('outfit');
  const [aspectRatio, setAspectRatio] = useState("3:4");
  const [faceLock, setFaceLock] = useState(true);

  // Dynamic Selections based on active tab
  const [outfitSel, setOutfitSel] = useState<Record<string, string>>({});
  const [bgSel, setBgSel] = useState<Record<string, string>>({});
  const [poseSel, setPoseSel] = useState<Record<string, string>>({});

  // Additional prompt
  const [customPrompt, setCustomPrompt] = useState("");

  // State for Generation
  const [loading, setLoading] = useState(false);
  const [progress, setProgress] = useState(0); // Progress bar state
  const [analyzing, setAnalyzing] = useState(false); // State for AI Analysis
  const [resultImage, setResultImage] = useState<string | null>(null);

  // History State
  const [history, setHistory] = useState<(string | null)[]>([]);

  const [error, setError] = useState<string | null>(null);

  // Zoom & Pan State
  const [zoom, setZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  // --- CROPPER STATE ---
  const [showCropModal, setShowCropModal] = useState(false);
  const [tempRefImg, setTempRefImg] = useState<string | null>(null);
  const [tempRefFile, setTempRefFile] = useState<File | null>(null);
  // cropRect coordinates are relative to the displayed image in the modal
  const [cropRect, setCropRect] = useState({ x: 0, y: 0, width: 0, height: 0 });
  const [isSelecting, setIsSelecting] = useState(false);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });

  const imgRef = useRef<HTMLImageElement>(null);
  const cropContainerRef = useRef<HTMLDivElement>(null);

  // Refs for file inputs
  const modelInputRef = useRef<HTMLInputElement>(null);
  const refInputRef = useRef<HTMLInputElement>(null);
  const progressInterval = useRef<ReturnType<typeof setInterval> | null>(null);

  // Reset result ONLY when the main uploaded photo changes
  useEffect(() => {
     setResultImage(null);
     setHistory([]); // Clear history when changing model
  }, [modelPhoto]);

  // Reset zoom/pan when result changes
  useEffect(() => {
    setZoom(1);
    setPan({ x: 0, y: 0 });
  }, [resultImage]);

  // Clear reference when switching tabs to avoid confusion
  useEffect(() => {
      setRefPhoto(null);
      setRefPreview(null);
  }, [activeTab]);

  // Handlers
  const handleModelUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      const file = e.target.files[0];
      setModelPhoto(file);
      setModelPreview(URL.createObjectURL(file));
      setResultImage(null);
    }
  };

  const handleRefUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      const file = e.target.files[0];
      // Instead of setting directly, open crop modal
      setTempRefFile(file);
      setTempRefImg(URL.createObjectURL(file));
      setCropRect({ x: 0, y: 0, width: 0, height: 0 }); // Reset crop
      setShowCropModal(true);
      // Reset input value so same file can be selected again if needed
      e.target.value = '';
    }
  };

  // --- CROPPER LOGIC ---
  const handleCropMouseDown = (e: React.MouseEvent) => {
      if (!cropContainerRef.current) return;
      const rect = cropContainerRef.current.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      setIsSelecting(true);
      setStartPos({ x, y });
      setCropRect({ x, y, width: 0, height: 0 });
  };

  const handleCropMouseMove = (e: React.MouseEvent) => {
      if (!isSelecting || !cropContainerRef.current) return;
      const rect = cropContainerRef.current.getBoundingClientRect();
      const currentX = Math.max(0, Math.min(e.clientX - rect.left, rect.width));
      const currentY = Math.max(0, Math.min(e.clientY - rect.top, rect.height));

      const newX = Math.min(startPos.x, currentX);
      const newY = Math.min(startPos.y, currentY);
      const newWidth = Math.abs(currentX - startPos.x);
      const newHeight = Math.abs(currentY - startPos.y);

      setCropRect({ x: newX, y: newY, width: newWidth, height: newHeight });
  };

  const handleCropMouseUp = () => {
      setIsSelecting(false);
  };

  const closeCropModal = () => {
      setShowCropModal(false);
      setTempRefImg(null);
      setTempRefFile(null);
  };

  const handleUseOriginal = () => {
      if (tempRefFile && tempRefImg) {
          setRefPhoto(tempRefFile);
          setRefPreview(tempRefImg);
      }
      setShowCropModal(false);
  };

  const handleProcessCrop = async () => {
      if (!imgRef.current || cropRect.width < 10 || cropRect.height < 10) {
          handleUseOriginal();
          return;
      }

      const image = imgRef.current;
      const canvas = document.createElement('canvas');

      // Calculate scaling factor between displayed image and natural image
      const scaleX = image.naturalWidth / image.width;
      const scaleY = image.naturalHeight / image.height;

      const realX = cropRect.x * scaleX;
      const realY = cropRect.y * scaleY;
      const realWidth = cropRect.width * scaleX;
      const realHeight = cropRect.height * scaleY;

      canvas.width = realWidth;
      canvas.height = realHeight;
      const ctx = canvas.getContext('2d');

      if (ctx) {
          ctx.drawImage(
              image,
              realX, realY, realWidth, realHeight,
              0, 0, realWidth, realHeight
          );

          canvas.toBlob((blob) => {
              if (blob) {
                  const croppedFile = new File([blob], "cropped_ref.jpg", { type: "image/jpeg" });
                  setRefPhoto(croppedFile);
                  setRefPreview(URL.createObjectURL(croppedFile));
                  setShowCropModal(false);
              }
          }, 'image/jpeg', 0.95);
      }
  };


  const handleResetResult = () => {
      setResultImage(null);
      setHistory([]); // Clear history on reset
  };

  const handleUndo = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (history.length === 0) return;

      const previousState = history[history.length - 1];
      setResultImage(previousState);
      setHistory(prev => prev.slice(0, -1));
  };

  const toggleSelection = (category: string, item: string) => {
    const setSel = activeTab === 'outfit' ? setOutfitSel 
                 : activeTab === 'bg' ? setBgSel 
                 : setPoseSel;

    setSel(prev => ({
      ...prev,
      [category]: prev[category] === item ? '' : item
    }));
  };

  const randomizeSelections = () => {
    let categories: any = {};
    let setSel: any = null;

    if (activeTab === 'outfit') { categories = OUTFIT_CATEGORIES; setSel = setOutfitSel; }
    else if (activeTab === 'bg') { categories = BG_CATEGORIES; setSel = setBgSel; }
    else { categories = POSE_CATEGORIES; setSel = setPoseSel; }

    const newSel: any = {};
    Object.keys(categories).forEach(cat => {
      const items = categories[cat];
      newSel[cat] = items[Math.floor(Math.random() * items.length)];
    });
    setSel(newSel);
  };

  const handleAIRecommendation = async () => {
      if (!modelPhoto) {
          setError("Silakan upload foto terlebih dahulu agar AI bisa menganalisis.");
          return;
      }

      setAnalyzing(true);
      setError(null);
      try {
          const promptRecommendation = await getOutfitRecommendations(modelPhoto);
          setCustomPrompt(promptRecommendation);
          // Clear manual selections to give full control to the AI prompt
          setOutfitSel({});
      } catch (err) {
          console.error("Analysis Failed", err);
          setError("Gagal mendapatkan rekomendasi AI. Silakan coba lagi.");
      } finally {
          setAnalyzing(false);
      }
  };

  const getActiveSelections = () => {
    if (activeTab === 'outfit') return outfitSel;
    if (activeTab === 'bg') return bgSel;
    return poseSel;
  };

  const getActiveCategories = () => {
    if (activeTab === 'outfit') return OUTFIT_CATEGORIES;
    if (activeTab === 'bg') return BG_CATEGORIES;
    return POSE_CATEGORIES;
  };

  // Helper to get progress message
  const getProgressMessage = () => {
      if (progress < 30) {
          if (activeTab === 'outfit') return "Menganalisis bentuk tubuh & hijab...";
          if (activeTab === 'bg') return "Memisahkan subjek dari background...";
          if (activeTab === 'pose') return "Mendeteksi struktur tulang...";
          return "Memulai proses...";
      } else if (progress < 70) {
          if (activeTab === 'outfit') return "Menjahit outfit baru secara digital...";
          if (activeTab === 'bg') return "Membangun lingkungan baru...";
          if (activeTab === 'pose') return "Menggenerasi pose baru...";
          return "Menggenerasi gambar...";
      } else {
          if (activeTab === 'outfit') return "Menyesuaikan tekstur kain & cahaya...";
          if (activeTab === 'bg') return "Blending cahaya & bayangan...";
          if (activeTab === 'pose') return "Menjaga kemiripan wajah...";
          return "Finishing sentuhan akhir...";
      }
  };

  const handleGenerate = async () => {
    setLoading(true);
    setProgress(0);
    setError(null);

    // Start progress simulation
    progressInterval.current = setInterval(() => {
        setProgress((prev) => {
            if (prev >= 90) return 90; // Hold at 90% until done
            // Slower increment as it gets higher
            const increment = prev < 50 ? 5 : 1; 
            return prev + increment;
        });
    }, 300);

    // Construct prompt
    const selections = getActiveSelections();
    const hasSelections = Object.values(selections).some(val => !!val);
    let prompt = "";

    if (activeTab === 'outfit') {
        // If no specific selections and no custom prompt, generate a rich default
        if (!hasSelections && !customPrompt) {
             prompt = "Seorang model fashion muslimah tampil memukau dengan gaya OOTD kekinian yang elegan. Menggunakan outfit modest wear premium dengan perpaduan warna earth tone yang lembut, hijab style modern yang rapi. Pencahayaan cinematic, resolusi 8k super detail, photorealistic masterpiece, tekstur kain nyata.";
        } else {
            const style = selections['Gaya'];
            const top = selections['Atasan'];
            const bottom = selections['Bawahan'];
            const hijab = selections['Hijab'];

            let description = "";

            // 1. Context & Style (The Vibe)
            if (style) {
                description = `Seorang model fashion muslimah memancarkan pesona ${style} yang anggun dan percaya diri.`;
            } else {
                description = "Seorang model fashion muslimah tampil menawan dengan gaya OOTD terkini.";
            }

            // 2. The Outfit (The Look)
            if (top && bottom) {
                description += ` Ia mengenakan kombinasi ${top} yang dipadukan secara estetik dengan ${bottom}.`;
            } else if (top) {
                description += ` Ia terlihat stylish mengenakan ${top} yang modis.`;
            } else if (bottom) {
                description += ` Ia mengenakan ${bottom} yang memberikan siluet elegan.`;
            }

            // 3. Hijab Detail
            if (hijab) {
                 description += ` Penampilannya semakin sempurna dengan balutan hijab ${hijab} yang rapi.`;
            }

            // 4. Custom Prompt & Aesthetics
            if (customPrompt) {
                description += ` Detail tambahan: ${customPrompt}.`;
            } else {
                // Contextual enhancers
                let enhancers = " Wajah cantik natural, proporsi tubuh ideal, pencahayaan studio yang soft, detail tekstur kain high-definition, photorealistic 8k.";

                if (style && (style.includes('Street') || style.includes('Casual') || style.includes('Sporty'))) {
                    enhancers = " Pencahayaan natural outdoor, gaya candid yang hidup, detail outfit tajam, depth of field, 8k uhd.";
                } else if (style && (style.includes('Formal') || style.includes('Office') || style.includes('Luxury'))) {
                    enhancers = " Pencahayaan elegan, kesan mewah, detail kain premium, fotografi editorial fashion, 8k.";
                }

                description += enhancers;
            }

            prompt = description;
        }
    } else {
        // BG or POSE
        if (!hasSelections && !customPrompt) {
             if (activeTab === 'bg') {
                 prompt = "Latar belakang aesthetic modern minimalist cafe dengan pencahayaan natural yang lembut, dekorasi tanaman hijau, suasana cozy dan hangat, bokeh background, resolusi tinggi 8k.";
             } else { // pose
                 prompt = "Pose fashion model profesional yang elegan dan natural, berdiri percaya diri dengan senyum lembut, tatapan mata tajam ke kamera, high fashion photography style.";
             }
        } else {
            const descriptionParts = Object.entries(selections)
            .filter(([_, val]) => val)
            .map(([key, val]) => `${key}: ${val}`);

            if (customPrompt) descriptionParts.push(customPrompt);
            prompt = descriptionParts.join(', ');
        }
    }

    // Fallback if prompt is still empty (e.g. user cleared everything)
    if (!prompt && !refPhoto) {
         if (activeTab === 'outfit') prompt = "Full body shot of a stylish muslimah model wearing trending hijab outfit, photorealistic, 8k, highly detailed";
         else if (activeTab === 'bg') prompt = "Beautiful aesthetic background, high quality";
         else prompt = "Model posing naturally, photorealistic";
    }

    // --- REINFORCE FACE LOCK AT PROMPT LEVEL ---
    if (faceLock) {
         prompt += ". STRICT REQUIREMENT: Keep the model's face, features, expression, and skin tone 100% identical to the original image. Do not edit the face.";
    }

    try {
        let url;
        let sourceImageFile = modelPhoto;

        // CHAINING LOGIC:
        if (resultImage) {
            try {
                sourceImageFile = await base64ToFile(resultImage, "edited_image.png");
            } catch (e) {
                console.warn("Failed to reuse result image, falling back to original", e);
                sourceImageFile = modelPhoto;
            }
        }

        if (sourceImageFile) {
             url = await generateVirtualTryOn(sourceImageFile, prompt, refPhoto, creativity, activeTab, aspectRatio, faceLock);
        } else {
             // Fallback: Text to Image
             if (activeTab !== 'outfit') {
                 setError("Upload foto terlebih dahulu untuk mengganti Background atau Pose.");
                 setLoading(false);
                 if (progressInterval.current) clearInterval(progressInterval.current);
                 return;
             }
             prompt += ". Full body shot of a muslimah model, photorealistic, 8k.";
             url = await generateOutfitImage(prompt, aspectRatio);
        }

        if (url) {
            // Save to history before updating
            setHistory(prev => [...prev, resultImage]);
            setResultImage(url);
        }
    } catch (err: any) {
        console.error("Generation Error:", err);

        let displayError = "Terjadi kesalahan saat memproses permintaan Anda.";
        const msg = (err.message || err.toString()).toLowerCase();

        if (msg.includes('401') || msg.includes('api key')) {
            displayError = "Akses ditolak: API Key tidak valid atau tidak ditemukan.";
        } else if (msg.includes('safety') || msg.includes('blocked')) {
             displayError = "Gambar tidak dapat dibuat karena melanggar kebijakan keamanan konten.";
        }

        setError(displayError);
    } finally {
        if (progressInterval.current) clearInterval(progressInterval.current);
        setProgress(100);
        setTimeout(() => setLoading(false), 600); // Slight delay to show 100% completion
    }
  };

  // Zoom Handlers
  const handleZoomIn = (e: React.MouseEvent) => {
    e.stopPropagation();
    setZoom(z => Math.min(z + 0.5, 4));
  };
  const handleZoomOut = (e: React.MouseEvent) => {
    e.stopPropagation();
    setZoom(z => {
      const newZoom = Math.max(z - 0.5, 1);
      if (newZoom === 1) setPan({ x: 0, y: 0 });
      return newZoom;
    });
  };
  const handleResetZoom = (e: React.MouseEvent) => {
    e.stopPropagation();
    setZoom(1); 
    setPan({x:0,y:0});
  };

  // Pan Handlers
  const handlePanStart = (e: React.MouseEvent | React.TouchEvent) => {
    if (zoom > 1) {
      setIsDragging(true);
      const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
      const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
      setDragStart({ x: clientX - pan.x, y: clientY - pan.y });
    }
  };

  const handlePanMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (isDragging && zoom > 1) {
      e.preventDefault(); // Prevent default scroll on mobile when panning
      const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
      const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
      setPan({
        x: clientX - dragStart.x,
        y: clientY - dragStart.y
      });
    }
  };

  const handlePanEnd = () => setIsDragging(false);


  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-in fade-in duration-500 pb-12">
      {/* Header */}
      <div className="text-center space-y-2 mb-8">
        <h1 className="text-3xl md:text-5xl font-serif font-bold text-stone-900">
          Al Hijab <span className="text-transparent bg-clip-text bg-gradient-to-r from-rose-500 to-purple-600">Magic Studio</span>
        </h1>
        <p className="text-stone-500 text-sm md:text-base">
          Virtual Makeover: Ganti gaya hijab, outfit, background, atau pose dengan AI
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* LEFT COLUMN - CONTROLS */}
        <div className="lg:col-span-5 space-y-6">

          {/* 1. FOTO EDITOR */}
          <div className="bg-white p-5 rounded-3xl shadow-sm border border-stone-100">
            <div className="flex items-center gap-2 mb-4">
              <div className="bg-rose-500 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">1</div>
              <h3 className="font-bold text-stone-800 tracking-wide text-sm">FOTO & MODE</h3>
            </div>

            {/* Main Upload Area */}
            <div className="mb-4">
              {!modelPreview ? (
                <div 
                  onClick={() => modelInputRef.current?.click()}
                  className="h-64 border-2 border-dashed border-stone-300 rounded-2xl flex flex-col items-center justify-center cursor-pointer hover:bg-stone-50 transition-all group"
                >
                  <div className="bg-rose-50 p-3 rounded-full mb-3 group-hover:bg-rose-100 transition-colors">
                    <Upload size={24} className="text-rose-500" />
                  </div>
                  <span className="text-stone-600 font-medium text-sm">Upload Foto OOTD</span>
                  <span className="text-stone-400 text-xs mt-1">Format JPG, PNG (Max 5MB)</span>
                </div>
              ) : (
                <div className="relative h-64 rounded-2xl overflow-hidden bg-stone-100 border border-stone-200 group">
                  <img src={modelPreview} alt="Model" className="w-full h-full object-cover" />

                  {/* Face Lock Overlay Button */}
                  <div className="absolute top-2 left-2 z-10">
                      <button
                          onClick={(e) => { e.stopPropagation(); setFaceLock(!faceLock); }}
